// S3 bucket: hogwarts-databayt | CloudFront: d1dlwtcfl0db67.cloudfront.net
export const CDN_BASE = "https://d1dlwtcfl0db67.cloudfront.net";

export interface Asset {
  key: string;
  url: string;
  sourceUrl: string;
  name: string;
  description: string;
  category: AssetCategory;
  format: "svg" | "png" | "jpg" | "webp" | "gif" | "json" | "pdf" | "woff2" | "ttf" | "ico" | "mp4" | "webm" | "wav";
  width?: number;
  height?: number;
  source: string;
  cdn: "databayt";
}

function a(
  key: string,
  sourceUrl: string,
  name: string,
  description: string,
  category: AssetCategory,
  format: Asset["format"],
  source: string,
  width?: number,
  height?: number,
): Asset {
  return {
    key,
    url: `${CDN_BASE}/${key}`,
    sourceUrl,
    name,
    description,
    category,
    format,
    source,
    cdn: "databayt",
    ...(width && height ? { width, height } : {}),
  };
}

